import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { WorkOrder } from '@/models/or';
import { User } from '@/models/user';
import { url } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'workOrders',
    template: () => import('./work-orders.html?raw'),
    data: () => ({
        user: null as User | null,
        nav: null as string | null,
        aside: null as string | null,
        loading: true,
        workOrders: [] as WorkOrder[],
        async init() {
            console.log('work-orders@init');

            this.nav = await render(nav);
            this.aside = await render(aside);

            this.user = await getAuthenticatedUser();

            await this.loadWorkOrders();
        },

        async loadWorkOrders() {
            this.loading = true;

            try {
                if (this.$router.route === '/or/me') {
                    const mecs = await fetch(url(`/isiWeb/web/v1/empresas/01/mecanicos?usuario=${this.user.usuario}`), {
                        credentials: 'include',
                    });

                    const mecsResponse = await mecs.json();

                    const r = await fetch(
                        url(`/isiWeb/web/v1/empresas/01/ordenes-reparacion?mec=${mecsResponse.data[0].mec}&fecrep:eq=`),
                        {
                            credentials: 'include',
                        },
                    );

                    const response = await r.json();

                    this.workOrders = response.data as WorkOrder[];
                }

                if (this.$router.route === '/or/list') {
                    const r = await fetch(
                        url(`/isiWeb/web/v1/empresas/01/ordenes-reparacion?almnro=${this.user.usuario}&fecrep:eq=`),
                        {
                            credentials: 'include',
                        },
                    );

                    const response = await r.json();

                    this.workOrders = response.data as WorkOrder[];
                }
            } catch (error: any) {
                this.error = error.message;
            }

            this.loading = false;
        },
    }),
} as ComponentModule;
